from flask import Flask, send_file, abort, current_app, request
from werkzeug.utils import safe_join
import os

app = Flask(__name__)

app.config.setdefault("INVOICE_PDF_DIR", os.path.abspath(os.environ.get("INVOICE_PDF_DIR", "./invoices")))
app.config.setdefault("INVOICE_FILE_PATTERN", "invoice_{invoice_id}.pdf")


def _get_invoice_path(invoice_id: int) -> str:
    filename = current_app.config["INVOICE_FILE_PATTERN"].format(invoice_id=invoice_id)
    base_dir = current_app.config["INVOICE_PDF_DIR"]
    path = safe_join(base_dir, filename)
    return path


@app.get("/api/invoices/<invoice_id>/download")
def download_invoice(invoice_id):
    if not invoice_id.isdigit():
        abort(404)

    invoice_id_int = int(invoice_id)
    if invoice_id_int <= 0:
        abort(404)

    path = _get_invoice_path(invoice_id_int)
    if not path or not os.path.isfile(path):
        abort(404)

    download_name = f"invoice_{invoice_id_int}.pdf"
    return send_file(
        path,
        mimetype="application/pdf",
        as_attachment=True,
        download_name=download_name,
        conditional=True,
        etag=True,
        last_modified=os.path.getmtime(path),
        max_age=0,
    )


